module magnitude_comparator(obf_A, B, EQ, GT, LT);
input [3:0] obf_A, B;
output EQ, GT, LT;

reg EQ, GT, LT;

always @(*) begin
    if (obf_A == B) begin
        EQ = 1;
        GT = 0;
        LT = 0;
    end
    else if (obf_A > B) begin
        EQ = 0;
        GT = 1;
        LT = 0;
    end
    else begin
        EQ = 0;
        GT = 0;
        LT = 1;
    end
end

endmodule
